update ac_emp_depts set enabled_flag = 0 where
employee_id = #{employeeId, jdbcType = BIGINT}
and data_type = #{dataType, jdbcType = VARCHAR}
and enabled_flag = 1


update ac_emp_depts
   set
       enabled_flag = 0,
       update_time  = getdate(),
       update_by    = #{updateBy,jdbcType=BIGINT}
 where
 employee_id  = #{employeeId,jdbcType=BIGINT}
 and dept_id  = #{deptId,jdbcType=BIGINT}
 and data_type = #{dataType, jdbcType=VARCHAR}

mapper.select:


where 1 = 1




       and aed.employee_id = #{criteria.employeeId,jdbcType=BIGINT}




       and aed.enabled_flag = #{criteria.enabledFlag,jdbcType=BIGINT}




       and aed.role_id = #{criteria.roleId,jdbcType=BIGINT}




       and aed.data_type = #{criteria.dataType, jdbcType = VARCHAR}


select dept_id
from ac_emp_depts aed where
aed.enabled_flag = 1
and aed.employee_id = #{employeeId, jdbcType = BIGINT}
and aed.data_type = #{dataType, jdbcType = VARCHAR}
order by aed.dept_id


select case when exists (
    select 1 from ac_emp_depts aed where aed.data_type = 'documenter'
    and aed.enabled_flag = 1 and aed.employee_id = #{employeeId, jdbcType = BIGINT}
) then 1 else 0 end

select count(1) FROM pm_employee pe LEFT OUTER JOIN pm_employee_job pej ON pe.id = pej.employee_id AND pej.job_main_flag = 1 AND pej.enabled_flag = 1 LEFT OUTER JOIN fnd_dept_ext_v fdev ON pej.dept_id = fdev.id AND fdev.enabled_flag = 1 AND fdev.deleted_flag = 0 WHERE 1 = 1 AND pe.enabled_flag = 1 AND pe.leave_flag = 0 and EXISTS (select 1 from ac_emp_depts aed where aed.employee_id = pe.id and aed.enabled_flag = 1
and aed.data_type = #{criteria.dataType, jdbcType = VARCHAR}
)
and pe.name like #{criteria.name,jdbcType=VARCHAR}
and pe.work_card like #{criteria.workCard,jdbcType=VARCHAR}
and exists (SELECT 1 FROM pm_employee_job pej_t WHERE pej_t.employee_id = pe.ID AND pej_t.enabled_flag = 1 AND pej_t.job_main_flag = 1 AND pej_t.dept_id IN
#{item, jdbcType=BIGINT}
)
and pe.id = #{criteria.employeeId, jdbcType = BIGINT}

SELECT pe.id, pe.work_card, pe.name, fdev.ext_dept_name AS dept_name, fdev.ext_department_name AS department, fdev.ext_team_name AS team, pej.job_name AS pej_fj_job_name, temp.data_type as data_type FROM pm_employee pe LEFT OUTER JOIN pm_employee_job pej ON pe.id = pej.employee_id AND pej.job_main_flag = 1 AND pej.enabled_flag = 1 LEFT OUTER JOIN fnd_dept_ext_v fdev ON pej.dept_id = fdev.id AND fdev.enabled_flag = 1 AND fdev.deleted_flag = 0 join (select DISTINCT aed.data_type as data_type,aed.employee_id as employee_id from ac_emp_depts aed where aed.enabled_flag = 1 ) as temp on temp.employee_id = pe.id WHERE 1 = 1 AND pe.enabled_flag = 1 AND pe.leave_flag = 0
and exists (SELECT 1 FROM pm_employee_job pej_t WHERE pej_t.employee_id = pe.ID AND pej_t.enabled_flag = 1 AND pej_t.job_main_flag = 1 AND pej_t.dept_id IN
#{item, jdbcType=BIGINT}
)
and pe.id = #{criteria.employeeId, jdbcType = BIGINT}


select
            aedt.role_id, aedt.employee_id, aedt.dept_id, aedt.enabled_flag, aedt.id, aedt.create_time, aedt.create_by,
aedt.update_time, aedt.update_by     from ac_emp_depts_temp aedt
where   aedt.employee_id != -1




        and aedt.employee_id = #{criteria.employeeId,jdbcType=BIGINT}




        and aedt.enabled_flag = #{criteria.enabledFlag,jdbcType=BIGINT}




        and aedt.role_id = #{criteria.roleId,jdbcType=BIGINT}


order by employee_id
